import android.app.Activity
import android.content.Intent
import android.os.Bundle
import com.facebook.*
import com.facebook.login.LoginManager
import com.google.android.gms.auth.api.signin.GoogleSignIn
import com.google.android.gms.auth.api.signin.GoogleSignInClient
import com.google.android.gms.auth.api.signin.GoogleSignInOptions

class MainActivity : AppCompatActivity() {
    private lateinit var googleSignInClient: GoogleSignInClient
    private val REQUEST_CODE = 101

    init {
        System.loadLibrary("facebook-android-sdk")
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        val gso = GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
            .requestEmail()
            .build()

        googleSignInClient = GoogleSignIn.getClient(this, gso)

        // Facebook Login Setup
        FacebookSdk.sdkInitialize(applicationContext)
        val facebook = Facebook.getInstance(this)
        facebook.setActiveSessionMonitor(object : ActiveSessionListener() {
            override fun onActiveSession(session: Session?, token: AccessToken?) {}
            override fun onDeactivatedSession(session: Session?, callback: Callback?) {
                LoginManager.getInstance().logOut()
            }
        })
    }

    fun signInWithGoogle(view: View) {
        val signInIntent = googleSignInClient.signInIntent
        startActivityForResult(signInIntent, REQUEST_CODE)
    }

    override fun onActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        if (requestCode == REQUEST_CODE) {
            val task = GoogleSignIn.getSignedInAccountFromIntent(data)
            val account = task.result
            if (account != null) {
                // Signed in successfully, do something with the account here
            }
        }

        super.onActivityResult(requestCode, resultCode, data)
    }

    fun signInWithFacebook(view: View) {
        LoginManager.getInstance().logInWithReadPermissions(this, Arrays.asList("email", "public_profile")) {
            if (it.isCancelled) {
                Log.d("Login", "Login canceled")
            } else if (it.grantedPermissions.contains("email")) {
                val request = GraphRequest(
                    AccessToken.getCurrentAccessToken(),
                    "/me?fields=email,name",
                    null
                )
                request.executeAsync()
            }
        }
    }
}